insert into public.cards (deck_id, type, text, param, is_persistent, needs_target, min_players, penalty, sort_order) values
  ((select id from public.decks where slug='start'), 'wooh', $j${"it":"Benvenuti a The WOOH Game! Se hai capito cos'è il WOOH, distribuisci 3 WOOH e tutti insieme urlate WOOH con il tono più assurdo che potete.","en":"Welcome to The WOOH Game! If you get what WOOH means, hand out 3 WOOH and everyone shouts WOOH in the most absurd tone possible."}$j$::jsonb, null, false, 0, 2, 1, 1),
  ((select id from public.decks where slug='start'), 'io_non_ho_mai', $j${"it":"Io non ho mai mandato un messaggio alla persona sbagliata. Chi l'ha fatto, beve.","en":"Never have I ever texted the wrong person. Whoever has, drinks."}$j$::jsonb, null, false, 0, 2, 1, 2),
  ((select id from public.decks where slug='start'), 'io_non_ho_mai', $j${"it":"Io non ho mai finto di aver capito una battuta che non avevo capito. Chi l'ha fatto, beve.","en":"Never have I ever pretended to get a joke I didn't get. Whoever has, drinks."}$j$::jsonb, null, false, 0, 2, 1, 3),
  ((select id from public.decks where slug='start'), 'io_non_ho_mai', $j${"it":"Io non ho mai cantato a squarciagola in macchina da solo. Chi l'ha fatto, beve.","en":"Never have I ever belted out a song alone in the car. Whoever has, drinks."}$j$::jsonb, null, false, 0, 2, 1, 4),
  ((select id from public.decks where slug='start'), 'tre_cose', $j${"it":"Di' 3 cose che hai nel telefono in questo momento e di cui un po' ti vergogni. Se non ne dici 3, bevi.","en":"Name 3 things in your phone right now that you're a little ashamed of. Can't name 3? Drink."}$j$::jsonb, null, false, 0, 2, 1, 5),
  ((select id from public.decks where slug='start'), 'tre_cose', $j${"it":"Le prime 3 cose che faresti se vincessi 10 milioni domani. Se non ne dici 3, bevi.","en":"The first 3 things you'd do if you won 10 million tomorrow. Can't name 3? Drink."}$j$::jsonb, null, false, 0, 2, 1, 6),
